// ECPay ReturnURL 伺服器端通知處理
// ECPay 用 POST application/x-www-form-urlencoded 呼叫此端點
// 必須回傳純文字 '1|OK' 否則 ECPay 會重試

const body = $input.first().json.body;

// 取得必要欄位
const merchantTradeNo = body.MerchantTradeNo;
const rtnCode = parseInt(body.RtnCode || '0');
const tradeAmt = parseInt(body.TradeAmt || '0');
const checkMacValue = body.CheckMacValue;

// ===== CheckMacValue 驗證 =====
// 注意：請將以下 HashKey / HashIV 替換為您的 ECPay 商家金鑰
const HASH_KEY = 'YOUR_ECPAY_HASH_KEY';  // ← 替換為實際值
const HASH_IV  = 'YOUR_ECPAY_HASH_IV';   // ← 替換為實際值

// 依 ECPay 規範計算 CheckMacValue
const crypto = require('crypto');

// 1. 移除 CheckMacValue 欄位，依鍵名字母排序，組成 query string
const params = { ...body };
delete params.CheckMacValue;

const sorted = Object.keys(params)
  .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()))
  .map(k => `${k}=${params[k]}`)
  .join('&');

const raw = `HashKey=${HASH_KEY}&${sorted}&HashIV=${HASH_IV}`;

// 2. URL encode → 小寫 → MD5
const encoded = encodeURIComponent(raw)
  .replace(/%20/g, '+')
  .replace(/!/g, '%21')
  .replace(/'/g, '%27')
  .replace(/\(/g, '%28')
  .replace(/\)/g, '%29')
  .replace(/\*/g, '%2A')
  .toLowerCase();

const computed = crypto.createHash('md5').update(encoded).digest('hex').toUpperCase();
const isValid = (computed === checkMacValue);

if (!isValid) {
  console.error('CheckMacValue 驗證失敗', { computed, received: checkMacValue });
}

// 計算到期日
const paidUntil = new Date();
if (tradeAmt >= 1999) {
  paidUntil.setFullYear(paidUntil.getFullYear() + 1);
} else {
  paidUntil.setMonth(paidUntil.getMonth() + 1);
}

return [{
  json: {
    isValid,
    isPaymentSuccess: rtnCode === 1,
    merchantTradeNo,
    rtnCode,
    tradeAmt,
    member_level: '付費會員',
    paid_until: paidUntil.toISOString()
  }
}];
